<?php
if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Todoist_API { const SYNC_BASE = 'https://api.todoist.com/sync/v9'; const REST_BASE = 'https://api.todoist.com/rest/v2'; public static function request( $method, $url, $token, $args = array() ) { $headers = array( 'Authorization' => 'Bearer ' . $token, ); $request_args = array( 'timeout' => 30, 'headers' => $headers, ); if ( 'POST' === strtoupper( $method ) ) { $request_args['body'] = $args; $resp = wp_remote_post( $url, $request_args ); } else { $url = add_query_arg( $args, $url ); $resp = wp_remote_get( $url, $request_args ); } if ( is_wp_error( $resp ) ) { return $resp; } $code = (int) wp_remote_retrieve_response_code( $resp ); $body = wp_remote_retrieve_body( $resp ); if ( $code < 200 || $code >= 300 ) { return new WP_Error( 'tct_todoist_http_error', 'Todoist API HTTP error: ' . $code, array( 'status_code' => $code, 'body' => $body, 'url' => $url, ) ); } if ( '' === trim( (string) $body ) ) { return array(); } $json = json_decode( $body, true ); if ( null === $json ) { return new WP_Error( 'tct_todoist_json_error', 'Todoist API returned invalid JSON.', array( 'body' => $body, 'url' => $url, ) ); } return $json; } public static function get_labels( $token ) { $url = self::SYNC_BASE . '/sync'; $body = array( 'sync_token' => '*', 'resource_types' => wp_json_encode( array( 'labels' ) ), ); return self::request( 'POST', $url, $token, $body ); } public static function get_completed_items( $token, $params = array() ) { $url = self::SYNC_BASE . '/completed/get_all'; $default = array( 'limit' => 200, 'offset' => 0, 'annotate_items' => 'true', ); $params = array_merge( $default, $params ); return self::request( 'GET', $url, $token, $params ); } public static function get_tasks( $token, $params = array() ) { $url = self::REST_BASE . '/tasks'; return self::request( 'GET', $url, $token, $params ); } public static function close_task( $token, $task_id ) { $task_id = sanitize_text_field( (string) $task_id ); if ( '' === $task_id ) { return new WP_Error( 'tct_todoist_missing_task_id', 'Missing task id.' ); } $url = self::REST_BASE . '/tasks/' . rawurlencode( $task_id ) . '/close'; return self::request( 'POST', $url, $token, array() ); } public static function reopen_task( $token, $task_id ) { $task_id = sanitize_text_field( (string) $task_id ); if ( '' === $task_id ) { return new WP_Error( 'tct_todoist_missing_task_id', 'Missing task id.' ); } $url = self::REST_BASE . '/tasks/' . rawurlencode( $task_id ) . '/reopen'; return self::request( 'POST', $url, $token, array() ); } } 
